import{_ as e,o,c as l,ag as t}from"./chunks/framework.DAY4Zhxq.js";const m=JSON.parse('{"title":"Ollama Cloud","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cloud.md","filePath":"guide/cloud.md"}'),i={name:"guide/cloud.md"};function r(n,a,s,d,c,u){return o(),l("div",null,[...a[0]||(a[0]=[t('<h1 id="ollama-cloud" tabindex="-1">Ollama Cloud <a class="header-anchor" href="#ollama-cloud" aria-label="Permalink to &quot;Ollama Cloud&quot;">​</a></h1><p>Alpaka Desktop supports <a href="https://ollama.com" target="_blank" rel="noreferrer">Ollama Cloud</a> for running models hosted on Ollama&#39;s infrastructure, in addition to local models.</p><h2 id="signing-in" tabindex="-1">Signing In <a class="header-anchor" href="#signing-in" aria-label="Permalink to &quot;Signing In&quot;">​</a></h2><ol><li>Go to <strong>Settings → Account</strong>.</li><li>Click <strong>Sign in with Ollama</strong>. The app polls for an OAuth token — your browser opens the Ollama sign-in page.</li><li>Complete sign-in in the browser. The app detects the token automatically and stores it in the system keyring.</li></ol><p>Your account status is shown in <strong>Settings → Account</strong>.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>For programmatic access or Ollama Cloud model pull requests, you may need an API key:</p><ol><li>Go to <strong>Settings → Account → API Keys</strong>.</li><li>Paste your Ollama Cloud API key.</li><li>Click <strong>Save</strong>. The key is validated against the API and stored in the system keyring — never in SQLite.</li><li>Click the trash icon to remove a saved key.</li></ol><h2 id="cloud-models" tabindex="-1">Cloud Models <a class="header-anchor" href="#cloud-models" aria-label="Permalink to &quot;Cloud Models&quot;">​</a></h2><p>Once signed in, Ollama Cloud models appear in the <strong>Models → Library</strong> tab alongside public models. Cloud models run on Ollama&#39;s infrastructure — you do not need to pull them locally.</p><p>All requests to <code>api.ollama.com</code> hosts automatically include the <code>Authorization: Bearer</code> header using your stored API key. If the key is missing, a friendly error appears in the chat instead of a raw network failure.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>Your conversations with local models never leave your machine. Conversations routed to Ollama Cloud hosts are subject to Ollama&#39;s privacy policy.</p>',13)])])}const p=e(i,[["render",r]]);export{m as __pageData,p as default};
